@namespace Lumeo

@if (Role == AgentMessageRole.System)
{
    <div class="@SystemClass" style="@BubbleMaxWidthStyle" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}
else if (Role == AgentMessageRole.Tool)
{
    <div class="@ToolWrapperClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}
else if (Role == AgentMessageRole.User)
{
    <div class="@UserRowClass" @attributes="AdditionalAttributes">
        <div class="flex min-w-0 flex-col items-end gap-1">
            @if (!string.IsNullOrEmpty(Name) || Timestamp.HasValue)
            {
                <div class="flex items-center gap-2 text-xs text-muted-foreground">
                    @if (Timestamp.HasValue)
                    {
                        <time datetime="@IsoTimestamp(Timestamp.Value)">@FormatTimestamp(Timestamp.Value)</time>
                    }
                    @if (!string.IsNullOrEmpty(Name))
                    {
                        <span class="font-medium text-foreground">@Name</span>
                    }
                </div>
            }
            <div class="@UserBubbleClass" style="@BubbleMaxWidthStyle">
                @ChildContent
                @if (IsStreaming)
                {
                    <span class="ms-0.5 inline-block align-baseline bg-current animate-pulse" style="width: 2px; height: 1em;">&nbsp;</span>
                }
            </div>
            @if (Actions is not null)
            {
                <div class="flex items-center justify-end gap-1 text-muted-foreground">
                    @Actions
                </div>
            }
        </div>
        @if (Avatar is not null)
        {
            <div class="shrink-0">@Avatar</div>
        }
    </div>
}
else
{
    <div class="@AssistantRowClass" @attributes="AdditionalAttributes">
        @if (Avatar is not null)
        {
            <div class="shrink-0 pt-0.5">@Avatar</div>
        }
        <div class="flex min-w-0 flex-1 flex-col gap-1">
            @if (!string.IsNullOrEmpty(Name) || Timestamp.HasValue)
            {
                <div class="flex items-center gap-2 text-xs text-muted-foreground">
                    @if (!string.IsNullOrEmpty(Name))
                    {
                        <span class="font-medium text-foreground">@Name</span>
                    }
                    @if (Timestamp.HasValue)
                    {
                        <time datetime="@IsoTimestamp(Timestamp.Value)">@FormatTimestamp(Timestamp.Value)</time>
                    }
                </div>
            }
            <div class="min-w-0 w-full text-sm leading-relaxed text-foreground">
                @ChildContent
                @if (IsStreaming)
                {
                    <span class="ms-0.5 inline-block align-baseline bg-current animate-pulse" style="width: 2px; height: 1em;">&nbsp;</span>
                }
            </div>
            @if (Actions is not null)
            {
                <div class="flex items-center gap-1 text-muted-foreground">
                    @Actions
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter] public AgentMessageRole Role { get; set; } = AgentMessageRole.Assistant;
    [Parameter] public RenderFragment? Avatar { get; set; }
    [Parameter] public string? Name { get; set; }
    [Parameter] public DateTimeOffset? Timestamp { get; set; }

    /// <summary>
    /// Time zone to render <see cref="Timestamp"/> in. When set, the timestamp
    /// is converted to this zone — pass the END USER'S zone here (in Blazor
    /// Server the component runs on the server, so the previous
    /// <c>ToLocalTime()</c> showed the SERVER'S zone, which is the bug #303
    /// fixed). When <c>null</c>, the timestamp is rendered in the offset it
    /// already carries (a <see cref="DateTimeOffset"/> knows its own offset), so
    /// it is deterministic and server-independent.
    /// </summary>
    [Parameter] public TimeZoneInfo? TimeZone { get; set; }

    /// <summary>Custom format string for the visible timestamp (default <c>"HH:mm"</c>).</summary>
    [Parameter] public string TimestampFormat { get; set; } = "HH:mm";

    /// <summary>Culture used to format the timestamp (defaults to <see cref="System.Globalization.CultureInfo.CurrentCulture"/>).</summary>
    [Parameter] public System.Globalization.CultureInfo? TimestampCulture { get; set; }

    [Parameter] public bool IsStreaming { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Optional actions toolbar rendered beneath the message body — typically an
    /// <see cref="AgentMessageActions"/> (copy / regenerate / retry) and/or an
    /// <see cref="AgentMessageBranchNav"/>. Only shown for User and Assistant turns.
    /// </summary>
    [Parameter] public RenderFragment? Actions { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string UserRowClass => Cx.Merge("flex items-start justify-end gap-3", Class);
    private string UserBubbleClass => "rounded-2xl bg-primary px-4 py-3 text-sm leading-relaxed text-primary-foreground shadow-sm";
    // max-w-[80%] is an arbitrary Tailwind class not in the pre-compiled utility
    // bundle — use inline style so the bubble actually caps.
    private const string BubbleMaxWidthStyle = "max-width: 80%;";

    private string AssistantRowClass => Cx.Merge("flex items-start gap-3", Class);

    private string SystemClass =>
        Cx.Merge("mx-auto rounded-[calc(var(--radius)*2)] bg-muted/60 px-3 py-1.5 text-center text-xs italic text-muted-foreground", Class);

    private string ToolWrapperClass => Cx.Merge("w-full", Class);

    // Render in the explicit TimeZone when supplied, otherwise in the offset the
    // DateTimeOffset already carries — never the server's local zone. Culture is
    // explicit so the displayed time doesn't drift with the server thread's
    // culture either.
    private string FormatTimestamp(DateTimeOffset ts)
    {
        var resolved = TimeZone is not null
            ? TimeZoneInfo.ConvertTime(ts, TimeZone)
            : ts;
        return resolved.ToString(TimestampFormat, TimestampCulture ?? System.Globalization.CultureInfo.CurrentCulture);
    }

    // Machine-readable, unambiguous source-of-truth for the <time> element:
    // always UTC ISO-8601 so assistive tech / client scripts can re-localize.
    private static string IsoTimestamp(DateTimeOffset ts) =>
        ts.UtcDateTime.ToString("yyyy-MM-ddTHH:mm:ssZ", System.Globalization.CultureInfo.InvariantCulture);

    public enum AgentMessageRole
    {
        User,
        Assistant,
        System,
        Tool
    }
}

@namespace Lumeo

@* A single icon action button for a message toolbar (shadcn `Action` parity).
   The Label is both the accessible name (aria-label + sr-only text) and, unless a
   separate Tooltip is given, the native title tooltip. *@
<button type="button"
        class="@ButtonClass"
        disabled="@Disabled"
        aria-label="@Label"
        title="@(Tooltip ?? Label)"
        @onclick="OnClick"
        @attributes="AdditionalAttributes">
    @if (ChildContent is not null)
    {
        @ChildContent
    }
    else if (Icon is not null)
    {
        <SvgGlyph Svg="@Icon" class="h-3.5 w-3.5" />
    }
    @if (!string.IsNullOrEmpty(Label))
    {
        <span class="sr-only">@Label</span>
    }
</button>

@code {
    /// <summary>Accessible name for the button — used for <c>aria-label</c>, the
    /// visually-hidden label, and the tooltip fallback. Required for a11y.</summary>
    [Parameter] public string? Label { get; set; }

    /// <summary>Icon to render (e.g. <c>LumeoIcons.Copy</c>). Ignored when
    /// <see cref="ChildContent"/> is supplied.</summary>
    [Parameter] public IconSource? Icon { get; set; }

    /// <summary>Native title tooltip; defaults to <see cref="Label"/> when unset.</summary>
    [Parameter] public string? Tooltip { get; set; }

    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public bool Disabled { get; set; }

    /// <summary>Custom button content (overrides <see cref="Icon"/>).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string ButtonClass => Cx.Merge(
        "inline-flex size-7 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-accent hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50",
        Class);
}

@namespace Lumeo
@inject Services.IComponentInteropService Interop
@inject Services.Localization.ILumeoLocalizer L
@implements IDisposable

@* Prebuilt message actions toolbar (shadcn Actions parity): a Copy button wired to
   the clipboard out of the box, plus optional Regenerate / Retry actions that render
   only when their callback is supplied. Drop extra <AgentMessageAction> children in
   via ChildContent. Intended for the AgentMessage `Actions` slot. *@
<div role="group" class="@GroupClass" aria-label="@L["AgentMessage.Actions"]" @attributes="AdditionalAttributes">
    @if (CopyText is not null)
    {
        <AgentMessageAction Icon="@(_copied ? LumeoIcons.Check : LumeoIcons.Copy)"
                            Label="@(_copied ? L["AgentMessage.Copied"] : L["AgentMessage.Copy"])"
                            OnClick="CopyAsync" />
    }
    @if (OnRegenerate.HasDelegate)
    {
        <AgentMessageAction Icon="@(LumeoIcons.RefreshCw)"
                            Label="@L["AgentMessage.Regenerate"]"
                            OnClick="OnRegenerate" />
    }
    @if (OnRetry.HasDelegate)
    {
        <AgentMessageAction Icon="@(LumeoIcons.RotateCcw)"
                            Label="@L["AgentMessage.Retry"]"
                            OnClick="OnRetry" />
    }
    @ChildContent
</div>

@code {
    /// <summary>Text copied to the clipboard by the built-in Copy action. When
    /// <c>null</c>, no Copy button is rendered.</summary>
    [Parameter] public string? CopyText { get; set; }

    /// <summary>Invoked after a successful copy (receives the copied text).</summary>
    [Parameter] public EventCallback<string> OnCopy { get; set; }

    /// <summary>When set, renders a Regenerate action invoking this callback.</summary>
    [Parameter] public EventCallback OnRegenerate { get; set; }

    /// <summary>When set, renders a Retry action invoking this callback.</summary>
    [Parameter] public EventCallback OnRetry { get; set; }

    /// <summary>Additional custom actions appended after the built-ins.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _copied;
    private CancellationTokenSource? _resetCts;

    private string GroupClass => Cx.Merge("flex items-center gap-0.5", Class);

    private async Task CopyAsync()
    {
        if (CopyText is null) return;
        // If the clipboard write fails we must NOT show the "Copied" confirmation
        // or fire OnCopy — nothing was copied. Bail out silently: the label stays
        // "Copy" so the user can retry. The failure modes we swallow:
        //   • JSDisconnectedException — dead Server circuit.
        //   • ObjectDisposedException — interop disposed during teardown.
        //   • JSException — the browser REJECTED the clipboard write itself: an
        //     insecure (non-HTTPS) origin has no navigator.clipboard, or the user
        //     denied the clipboard permission. This surfaces from the JS interop as
        //     a plain JSException (NOT a disconnect), so without this catch the Copy
        //     button would THROW instead of taking the silent no-op path.
        // Surfacing a visible error state is left to consumers via OnCopy-less flows
        // (no extra parameter added).
        try { await Interop.CopyToClipboard(CopyText); }
        catch (JSDisconnectedException) { return; }
        catch (ObjectDisposedException) { return; }
        catch (JSException) { return; }

        _copied = true;
        StateHasChanged();

        if (OnCopy.HasDelegate)
            await OnCopy.InvokeAsync(CopyText);

        // Revert the "Copied" affordance after a moment. Cancel any in-flight revert
        // so rapid re-copies keep showing the confirmation.
        _resetCts?.Cancel();
        _resetCts?.Dispose();
        _resetCts = new CancellationTokenSource();
        _ = ResetCopiedAsync(_resetCts.Token);
    }

    private async Task ResetCopiedAsync(CancellationToken token)
    {
        try { await Task.Delay(2000, token); }
        catch (TaskCanceledException) { return; }
        if (token.IsCancellationRequested) return;
        _copied = false;
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _resetCts?.Cancel();
        _resetCts?.Dispose();
    }
}

@namespace Lumeo
@inject Services.Localization.ILumeoLocalizer L

@* Branch navigation for messages that have alternate versions (shadcn
   MessageBranch* parity): previous / next buttons around an "N of M" page
   indicator. The nav is presentational — it emits the new 0-based index via
   IndexChanged and the consumer swaps in the matching branch content. *@
<div class="@RootClass" role="group" aria-label="@PageLabel" @attributes="AdditionalAttributes">
    <AgentMessageAction Icon="@(LumeoIcons.ChevronLeft)"
                        Label="@L["AgentMessage.PreviousBranch"]"
                        Disabled="@PrevDisabled"
                        OnClick="PreviousAsync"
                        Class="size-6" />
    <span class="px-1 text-xs tabular-nums text-muted-foreground" aria-hidden="true">@PageLabel</span>
    <AgentMessageAction Icon="@(LumeoIcons.ChevronRight)"
                        Label="@L["AgentMessage.NextBranch"]"
                        Disabled="@NextDisabled"
                        OnClick="NextAsync"
                        Class="size-6" />
</div>

@code {
    /// <summary>Current branch, 0-based. Two-way bindable via <c>@bind-Index</c>.</summary>
    [Parameter] public int Index { get; set; }
    [Parameter] public EventCallback<int> IndexChanged { get; set; }

    /// <summary>Total number of branches.</summary>
    [Parameter] public int Count { get; set; }

    /// <summary>When <c>true</c>, previous/next wrap around the ends instead of
    /// disabling at the first/last branch.</summary>
    [Parameter] public bool Loop { get; set; }

    /// <summary>Invoked (after <see cref="IndexChanged"/>) when moving to the previous branch.</summary>
    [Parameter] public EventCallback OnPrevious { get; set; }

    /// <summary>Invoked (after <see cref="IndexChanged"/>) when moving to the next branch.</summary>
    [Parameter] public EventCallback OnNext { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClass => Cx.Merge("inline-flex items-center gap-0.5 text-muted-foreground", Class);

    // 1-based, clamped for display so a stray out-of-range Index never shows "0 of 3".
    private int DisplayIndex => Count == 0 ? 0 : ClampedIndex + 1;
    private string PageLabel => L["AgentMessage.BranchXofY", DisplayIndex, Count];

    private bool PrevDisabled => Count <= 1 || (!Loop && Index <= 0);
    private bool NextDisabled => Count <= 1 || (!Loop && Index >= Count - 1);

    // Clamp a possibly-stale bound Index into range BEFORE stepping so we never emit an
    // out-of-range value. With Count==3 and a stale Index==4 the display already clamps to
    // "3 of 3", so Previous must step from the last valid index (2 → 1), not the raw 4
    // (which would emit 3). Symmetric for a stale negative Index on the Next side.
    private int ClampedIndex => Count == 0 ? 0 : Math.Clamp(Index, 0, Count - 1);

    private async Task PreviousAsync()
    {
        if (Count <= 1) return;
        var next = ClampedIndex - 1;
        if (next < 0)
        {
            if (!Loop) return;
            next = Count - 1;
        }
        await SetIndexAsync(next);
        if (OnPrevious.HasDelegate)
            await OnPrevious.InvokeAsync();
    }

    private async Task NextAsync()
    {
        if (Count <= 1) return;
        var next = ClampedIndex + 1;
        if (next >= Count)
        {
            if (!Loop) return;
            next = 0;
        }
        await SetIndexAsync(next);
        if (OnNext.HasDelegate)
            await OnNext.InvokeAsync();
    }

    private async Task SetIndexAsync(int next)
    {
        Index = next;
        if (IndexChanged.HasDelegate)
            await IndexChanged.InvokeAsync(next);
    }
}

using System.Globalization;
using System.Text;

namespace Lumeo;

public partial class AgentMessageList
{
    /// <summary>
    /// A single conversation turn used by <see cref="ToMarkdown"/>. Because
    /// <c>AgentMessage</c> bodies are arbitrary <c>RenderFragment</c>s (whose
    /// text can't be reliably extracted), the export takes the plain text explicitly.
    /// </summary>
    /// <param name="Role">The turn's role (drives the heading label).</param>
    /// <param name="Text">The message body as plain text / Markdown.</param>
    /// <param name="Name">Optional display name; overrides the default role label.</param>
    /// <param name="Timestamp">Optional timestamp appended to the heading.</param>
    public sealed record AgentMessageMarkdown(
        AgentMessage.AgentMessageRole Role,
        string Text,
        string? Name = null,
        DateTimeOffset? Timestamp = null);

    /// <summary>
    /// Serializes a conversation to a Markdown transcript — each turn becomes a bold
    /// role heading (with optional name + timestamp) followed by its body. Pair with
    /// <see cref="Services.IComponentInteropService.DownloadFile"/> to offer a download.
    /// </summary>
    /// <param name="messages">The turns, in display order.</param>
    /// <param name="title">Optional H2 title for the transcript.</param>
    /// <param name="timestampFormat">Format for turn timestamps (default <c>"yyyy-MM-dd HH:mm"</c>).</param>
    public static string ToMarkdown(
        IEnumerable<AgentMessageMarkdown> messages,
        string? title = null,
        string timestampFormat = "yyyy-MM-dd HH:mm")
    {
        ArgumentNullException.ThrowIfNull(messages);

        var sb = new StringBuilder();
        if (!string.IsNullOrWhiteSpace(title))
            sb.Append("## ").Append(title!.Trim()).Append("\n\n");

        foreach (var m in messages)
        {
            sb.Append("**").Append(RoleLabel(m.Role, m.Name)).Append("**");
            if (m.Timestamp is { } ts)
                sb.Append(" — ").Append(ts.ToString(timestampFormat, CultureInfo.InvariantCulture));
            sb.Append("\n\n");
            sb.Append((m.Text ?? string.Empty).Trim()).Append("\n\n");
        }

        return sb.ToString().TrimEnd('\n') + "\n";
    }

    private static string RoleLabel(AgentMessage.AgentMessageRole role, string? name) =>
        !string.IsNullOrWhiteSpace(name)
            ? name!.Trim()
            : role switch
            {
                AgentMessage.AgentMessageRole.User => "User",
                AgentMessage.AgentMessageRole.Assistant => "Assistant",
                AgentMessage.AgentMessageRole.System => "System",
                AgentMessage.AgentMessageRole.Tool => "Tool",
                _ => "Message",
            };
}

@namespace Lumeo
@inject Services.IComponentInteropService Interop
@inject Services.Localization.ILumeoLocalizer L
@implements IAsyncDisposable

<div id="@_listId" class="@RootClass" role="log" aria-live="polite" aria-relevant="additions" @attributes="AdditionalAttributes">
    @if (IsEmpty)
    {
        @* Empty state (shadcn ConversationEmptyState parity): the EmptyState slot
           when supplied, otherwise a sensible localized default. Centred in the
           scroll viewport. *@
        <div class="flex min-h-full flex-1 flex-col items-center justify-center gap-1 px-6 py-10 text-center">
            @if (EmptyState is not null)
            {
                @EmptyState
            }
            else
            {
                <p class="text-sm font-medium text-foreground">@L["AgentMessageList.EmptyTitle"]</p>
                <p class="text-sm text-muted-foreground">@L["AgentMessageList.EmptyDescription"]</p>
            }
        </div>
    }
    else if (Virtualize && Items is not null)
    {
        @* Virtualized path: <Virtualize> must sit directly inside the scroll
           container so its spacer elements measure correctly, so the flex-gap
           wrapper used by the default path is replaced with per-item bottom
           padding. Each item is a RenderFragment the consumer supplies. *@
        <Virtualize TItem="RenderFragment" Items="VirtualizedItems" ItemSize="ItemSize" OverscanCount="OverscanCount" Context="message">
            <div class="pb-4">
                @message
            </div>
        </Virtualize>
    }
    else
    {
        <div class="flex flex-col gap-4">
            @ChildContent
        </div>
    }

    @if (ShowScrollButton)
    {
        @* Floating scroll-to-latest button. A zero-height sticky wrapper keeps the
           button pinned to the bottom edge of the scroll viewport without reserving
           any layout space or clipping. It only becomes interactive once the JS
           observer reports the list is scrolled away from the bottom. *@
        <div class="pointer-events-none sticky bottom-0 z-20 flex justify-center" style="height:0;">
            @if (_scrolledAway)
            {
                <button type="button" @onclick="ScrollToLatestAsync"
                        data-testid="agent-scroll-button"
                        class="pointer-events-auto -translate-y-3 inline-flex size-8 items-center justify-center rounded-[calc(var(--radius)*3)] border border-border/60 bg-background/90 text-muted-foreground shadow-md backdrop-blur transition hover:bg-accent hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                        aria-label="@L["AgentMessageList.ScrollToLatest"]">
                    <SvgGlyph Svg="@(LumeoIcons.ArrowDown)" class="h-4 w-4" />
                    <span class="sr-only">@L["AgentMessageList.ScrollToLatest"]</span>
                </button>
            }
        </div>
    }
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool AutoScroll { get; set; } = true;

    /// <summary>
    /// Opt-in virtualization for long threads. When <c>true</c> AND
    /// <see cref="Items"/> is supplied, messages render through
    /// <see cref="Microsoft.AspNetCore.Components.Web.Virtualization.Virtualize{TItem}"/>
    /// so only the rows near the viewport are in the DOM. Leave <c>false</c> to
    /// use the simple <see cref="ChildContent"/> path (unchanged default).
    /// </summary>
    [Parameter] public bool Virtualize { get; set; }

    /// <summary>
    /// The per-message render fragments to virtualize. Each entry is rendered as
    /// one row (typically an <c>AgentMessage</c>). Only used when
    /// <see cref="Virtualize"/> is <c>true</c>; ignored otherwise.
    /// </summary>
    [Parameter] public IReadOnlyList<RenderFragment>? Items { get; set; }

    /// <summary>Estimated row height in pixels for the virtualizer (default 80).</summary>
    [Parameter] public float ItemSize { get; set; } = 80f;

    /// <summary>Extra rows to render above/below the viewport to smooth scrolling (default 4).</summary>
    [Parameter] public int OverscanCount { get; set; } = 4;

    /// <summary>
    /// When <c>true</c> (default), shows a floating scroll-to-latest button that
    /// appears whenever the list is scrolled away from the bottom and, when clicked,
    /// jumps back to the newest message. Screen-reader labelled. Set <c>false</c> to
    /// hide it (e.g. lists that are never longer than the viewport).
    /// </summary>
    [Parameter] public bool ShowScrollButton { get; set; } = true;

    /// <summary>
    /// Renders in place of the messages when <see cref="IsEmpty"/> is <c>true</c>
    /// (shadcn <c>ConversationEmptyState</c> parity). When <c>null</c>, a localized
    /// default title + description is shown instead.
    /// </summary>
    [Parameter] public RenderFragment? EmptyState { get; set; }

    /// <summary>
    /// When <c>true</c>, the <see cref="EmptyState"/> slot (or the built-in default)
    /// is rendered instead of the message content. The consumer drives this since the
    /// list can't introspect an arbitrary <see cref="ChildContent"/>.
    /// </summary>
    [Parameter] public bool IsEmpty { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _listId = LumeoIds.New("agent-message-list");
    private bool _observerRegistered;
    private bool _scrollButtonRegistered;
    private bool _scrolledAway;
    private DotNetObjectReference<AgentMessageList>? _selfRef;

    // Virtualize<TItem>.Items wants an ICollection<TItem>. Materialize it only
    // when the bound Items reference changes — recomputing (and copying, when
    // Items isn't already a collection) on every render would be O(n) per frame
    // during streaming and defeat virtualization.
    private IReadOnlyList<RenderFragment>? _itemsSnapshot;
    private ICollection<RenderFragment> _virtualizedItems = System.Array.Empty<RenderFragment>();
    private ICollection<RenderFragment> VirtualizedItems => _virtualizedItems;

    protected override void OnParametersSet()
    {
        if (!ReferenceEquals(_itemsSnapshot, Items))
        {
            _itemsSnapshot = Items;
            _virtualizedItems = Items as ICollection<RenderFragment>
                ?? Items?.ToList()
                ?? (ICollection<RenderFragment>)System.Array.Empty<RenderFragment>();
        }
    }

    private string RootClass =>
        // min-h-0 is essential: as a scroll container this is almost always a flex
        // child (the standard chat layout is a flex column of header + this list +
        // input). A flex child defaults to min-height:auto, which refuses to shrink
        // below its content — so without min-h-0 the list GROWS when a message expands
        // (e.g. a ReasoningDisplay opening) instead of scrolling, pushing the fixed
        // container taller. min-h-0 lets it shrink so overflow-y-auto actually scrolls.
        Cx.Merge("flex w-full min-h-0 flex-col overflow-y-auto", Class);

    // Reconcile the auto-scroll observer against the LIVE AutoScroll state on
    // every render rather than latching it on firstRender. Latching meant a
    // runtime toggle had no effect: AutoScroll flipped true→false never tore the
    // observer down, and false→true never registered it. OnAfterRenderAsync runs
    // after every render, so this picks up the current value as soon as it
    // changes. ai.observeAutoScroll already tears down a prior registration for
    // the same id, so re-registration is safe.
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        try
        {
            if (AutoScroll && !_observerRegistered)
            {
                _observerRegistered = true;
                await Interop.AiObserveAutoScroll(_listId);
            }
            else if (!AutoScroll && _observerRegistered)
            {
                _observerRegistered = false;
                await Interop.AiDisposeAutoScroll(_listId);
            }

            // Reconcile the scroll-button observer against the live ShowScrollButton
            // state on every render (same rationale as the auto-scroll observer above).
            if (ShowScrollButton && !_scrollButtonRegistered)
            {
                _scrollButtonRegistered = true;
                _selfRef ??= DotNetObjectReference.Create(this);
                await Interop.AiObserveScrollButton(_listId, _selfRef);
            }
            else if (!ShowScrollButton && _scrollButtonRegistered)
            {
                _scrollButtonRegistered = false;
                _scrolledAway = false;
                await Interop.AiDisposeScrollButton(_listId);
            }
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    /// <summary>
    /// Invoked from JS whenever the list crosses the "scrolled away from bottom"
    /// threshold, toggling the scroll-to-latest button's visibility.
    /// </summary>
    [JSInvokable]
    public void OnScrollAwayChanged(bool away)
    {
        if (_scrolledAway == away) return;
        _scrolledAway = away;
        StateHasChanged();
    }

    private async Task ScrollToLatestAsync()
    {
        // Optimistically hide the button; the JS observer will re-show it if the user
        // scrolls back up after the jump.
        _scrolledAway = false;
        try { await Interop.AiScrollToBottom(_listId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (_observerRegistered)
        {
            try
            {
                await Interop.AiDisposeAutoScroll(_listId);
            }
            catch (JSDisconnectedException) { /* ignore — circuit already gone */ }
        }
        if (_scrollButtonRegistered)
        {
            try
            {
                await Interop.AiDisposeScrollButton(_listId);
            }
            catch (JSDisconnectedException) { /* ignore — circuit already gone */ }
        }
        _selfRef?.Dispose();
    }
}
